  EVALUASI = 'Rapat Evaluasi Bulanan'
}

import { GoogleGenAI } from "@google/genai";
import { MeetingData } from "../types";

export const generateProfessionalMinutes = async (data: MeetingData): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  const prompt = `
    Sebagai Sekretaris Ahli Kepala Sekolah yang profesional, berwibawa, namun ramah, susunlah Notulen Rapat yang rapi berdasarkan data berikut:

    JUDUL RAPAT: ${data.title}
    HARI/TANGGAL: ${data.date}
    WAKTU: ${data.time}
    TEMPAT: ${data.location}
    PIMPINAN RAPAT: ${data.leadBy}
    PESERTA: ${data.participants}
    AGENDA: ${data.agenda}
    POIN DISKUSI: ${data.discussionPoints}
    KEPUTUSAN: ${data.decisions}
    TINDAK LANJUT: ${data.nextSteps}

    INSTRUKSI FORMAT:
    1. Gunakan Bahasa Indonesia formal yang baku (PUEBI).
    2. Struktur dokumen harus mencakup: Kepala Notulen, Agenda, Jalannya Rapat (Narasi singkat), Keputusan Akhir, dan Penutup.
    3. Gunakan nada bicara yang objektif namun menunjukkan dedikasi sekolah terhadap kualitas pendidikan.
    4. Pastikan hasil akhirnya siap cetak dengan format Markdown yang elegan.
    5. Tambahkan bagian tanda tangan untuk Notulis dan Mengetahui Kepala Sekolah di bagian akhir.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        temperature: 0.7,
        topP: 0.95,
      },
    });

    return response.text || "Maaf, terjadi kesalahan saat menyusun notulen.";
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw new Error("Gagal menghubungi layanan AI. Silakan coba lagi.");
  }
};

