import { generateProfessionalMinutes } from './services/geminiService';

const App: React.FC = () => {
  const [formData, setFormData] = useState<MeetingData>({
    title: '',
    date: '',
    time: '',
    location: '',
    leadBy: '',
    participants: '',
    agenda: '',
    discussionPoints: '',
    decisions: '',
    nextSteps: ''
  });

  const [isLoading, setIsLoading] = useState(false);
  const [generatedContent, setGeneratedContent] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoading(true);
    setError(null);

    try {
      const result = await generateProfessionalMinutes(formData);
      setGeneratedContent(result);
      // Scroll to result on small screens
      if (window.innerWidth < 768) {
        window.scrollTo({ top: document.body.scrollHeight, behavior: 'smooth' });
      }
    } catch (err: any) {
      setError(err.message || "Terjadi kesalahan yang tidak terduga.");
    } finally {
      setIsLoading(false);
    }
  };

  const handleCopy = useCallback(() => {
    if (generatedContent) {
      navigator.clipboard.writeText(generatedContent);
      alert("Notulen berhasil disalin ke clipboard!");
    }
  }, [generatedContent]);

  const handleReset = useCallback(() => {
    if (confirm("Apakah Anda yakin ingin menghapus draf ini?")) {
      setGeneratedContent(null);
    }
  }, []);

  return (
    <div className="min-h-screen pb-20">
      <Header />

      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        {error && (
          <div className="mb-6 p-4 bg-red-50 border-l-4 border-red-500 text-red-700 flex items-center gap-3">
            <i className="fas fa-exclamation-triangle"></i>
            {error}
