        <div className="grid grid-cols-1 lg:grid-cols-12 gap-8 items-start">
          {/* Left Side: Form */}
          <div className={`lg:col-span-5 ${generatedContent ? 'hidden lg:block' : 'lg:col-span-12 max-w-3xl mx-auto w-full'}`}>
            <MeetingForm 
              formData={formData} 
              setFormData={setFormData} 
              onSubmit={handleSubmit} 
              isLoading={isLoading} 
            />
          </div>

          {/* Right Side: Preview */}
          <div className={`lg:col-span-7 ${!generatedContent ? 'hidden' : 'block'}`}>
            <MinutesPreview 
              content={generatedContent || ''} 
              onCopy={handleCopy} 
              onReset={handleReset} 
            />
          </div>
        </div>

        {!generatedContent && !isLoading && (
          <div className="mt-12 max-w-4xl mx-auto text-center space-y-8 animate-fadeIn">
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
              <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100">
                <div className="w-12 h-12 bg-amber-100 text-amber-600 rounded-full flex items-center justify-center mx-auto mb-4">
                  <i className="fas fa-bolt text-xl"></i>
                </div>
                <h3 className="font-bold text-slate-800 mb-2">Instan & Cerdas</h3>
                <p className="text-slate-500 text-sm">Ubah poin kasar menjadi dokumen formal dalam hitungan detik.</p>
              </div>
              <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100">
                <div className="w-12 h-12 bg-blue-100 text-blue-600 rounded-full flex items-center justify-center mx-auto mb-4">
                  <i className="fas fa-balance-scale text-xl"></i>
                </div>
                <h3 className="font-bold text-slate-800 mb-2">Baku & Berwibawa</h3>
                <p className="text-slate-500 text-sm">Gaya bahasa profesional sesuai standar administrasi sekolah.</p>
              </div>
              <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100">
                <div className="w-12 h-12 bg-green-100 text-green-600 rounded-full flex items-center justify-center mx-auto mb-4">
                  <i className="fas fa-check-double text-xl"></i>
                </div>
                <h3 className="font-bold text-slate-800 mb-2">Siap Cetak</h3>
                <p className="text-slate-500 text-sm">Format rapi yang siap dibagikan kepada guru atau komite.</p>
              </div>
