            <div className="bg-slate-900 text-white p-8 rounded-2xl overflow-hidden relative shadow-2xl">
              <div className="relative z-10">
                <h2 className="text-2xl font-serif font-bold mb-4">Mulai Membangun Administrasi Sekolah yang Modern</h2>
                <p className="text-slate-400 max-w-2xl mx-auto mb-0">
